/// <summary>
/// SysOperation contract class for posting packing slips through the ETGSPAINSalesPackingSlipImport table
/// for the ETGSPAIN model.
/// </summary>
[DataContractAttribute]
class ETGSPAINSalesPackingSlipImportPostContract 
{
    private Set						    recordCollection;
    private ETGSPAINSalesPackingSlipImport   callerBuffer;
    private boolean					    refreshAll;
    TransDate                           transDate;
    str								    strQuery;
    boolean							    displayQueryFilter;    

}

Method.Source:
/// <summary>
/// Method to set the <c>recordCollection</c> variable.
/// </summary>
/// <param name = "_recordCollection">Set</param>
/// <returns>Set</returns>
[DataMember, AifCollectionType('return', Types::Int64), SysOperationControlVisibility(false)]
internal Set parmRecordCollection(Set _recordCollection = recordCollection)
{
    recordCollection = _recordCollection;
    return recordCollection;
}

/// <summary>
/// Method to set the <c>callerBuffer</c> variable.
/// </summary>
/// <param name = "_callerBuffer">ETGSPAINSalesPackingSlipImport</param>
/// <returns>ETGSPAINSalesPackingSlipImport</returns>
[DataMember, SysOperationControlVisibility(false)]
internal ETGSPAINSalesPackingSlipImport parmCallerBuffer(ETGSPAINSalesPackingSlipImport _callerBuffer = callerBuffer)
{
    callerBuffer = _callerBuffer;
    return callerBuffer;
}

/// <summary>
/// Method to set the <c>refreshAll</c> variable.
/// </summary>
/// <param name = "_refreshAll">boolean</param>
/// <returns>boolean</returns>
[DataMember, SysOperationControlVisibility(false)]
internal boolean parmRefreshAll(boolean _refreshAll = refreshAll)
{
    refreshAll = _refreshAll;
    return refreshAll;
}

/// <summary>
/// Method to set the <c>displayQueryFilter</c> variable.
/// </summary>
/// <param name = "_displayQueryFilter">boolean</param>
/// <returns>boolean</returns>
[DataMember, SysOperationControlVisibility(false)]
internal boolean parmDisplayQueryFilter(boolean _displayQueryFilter = displayQueryFilter)
{
    displayQueryFilter = _displayQueryFilter;
    return displayQueryFilter;
}

/// <summary>
/// Method to set the <c>strQuery</c> variable.
/// </summary>
/// <param name = "_strQuery">str</param>
/// <returns>str</returns>
[DataMember, AifQueryTypeAttribute('_strQuery', queryStr(ETGSPAINSalesPackingSlipImportQuery))]
public str parmQuery(str _strQuery = strQuery)
{
    strQuery = _strQuery;

    return strQuery;
}

/// <summary>
/// Method to set the <c>transDate</c> variable.
/// </summary>
/// <param name = "_transDate">TransDate</param>
/// <returns>TransDate</returns>
[DataMember]
public TransDate parmTransDate(TransDate _transDate = transDate)
{
    transDate = _transDate;

    return transDate;
}

/// <summary>
/// Method to retrieve the stored query, decoded.
/// </summary>
/// <returns>Query</returns>
public Query getQuery()
{
    return new Query (SysOperationHelper::base64Decode(strQuery));
}

/// <summary>
/// Method to set the query and encode it.
/// </summary>
/// <param name = "_query">Query</param>
public void setQuery(Query _query)
{
    strQuery = SysOperationHelper::base64Encode(_query.pack());
}

/// <summary>
/// Initializes the query.
/// </summary>
public void initQuery()
{
    Query query;

    query = this.getQuery();

    this.setQuery(query);
}
